import Community from '../models/Community.js';
import Canvas from '../models/Canvas.js';

// TODO: figure out how to type the return value of this;
// HydratedDocument<CanvasDetails> doesn't work

/**
 * Enforces that the community exists, and fetches the Canvas in MongoDB,
 * creating if one doesn't already exist for the community.
 * @param title Title of the canvas / community
 * @returns Mongoose document of Canvas
 */
const fetchCanvas = async (title: string) => {
  // enforce that community exists, create new canvas if necessary
  const community = await Community.findOne({ title });
  if (!community) {
    throw new Error('Community does not exist');
  }

  let fetchedCanvas = await Canvas.findOne({ title });
  if (!fetchedCanvas) {
    // create new canvas
    const newCanvas = new Canvas({
      title,
      strokes: [],
      baseImage:
        '',
    });
    fetchedCanvas = await newCanvas.save();
  }

  return fetchedCanvas;
};

export default fetchCanvas;
